/**
 * @summary List task assignments (filtered by status or assignee)
 */
export const getGetTaskAssignmentsUrl = (params?: GetTaskAssignmentsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/tasks?${stringifiedParams}`
    : `/api/tasks`;
};

export const getTaskAssignments = async (
  params?: GetTaskAssignmentsParams,
  options?: RequestInit,
): Promise<TaskAssignment[]> => {
  return customFetch<TaskAssignment[]>(getGetTaskAssignmentsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetTaskAssignmentsQueryKey = (
  params?: GetTaskAssignmentsParams,
) => {
  return [`/api/tasks`, ...(params ? [params] : [])] as const;
};

export const getGetTaskAssignmentsQueryOptions = <
  TData = Awaited<ReturnType<typeof getTaskAssignments>>,
  TError = ErrorType<unknown>,
>(
  params?: GetTaskAssignmentsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getTaskAssignments>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetTaskAssignmentsQueryKey(params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getTaskAssignments>>
  > = ({ signal }) => getTaskAssignments(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getTaskAssignments>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

